<?php require_once __DIR__.'/../../includes/bootstrap.php'; require_admin(); $repo=new app\Repositories\UserRepository(); $rows=$repo->all(); $roles=$repo->roles(); if($_SERVER['REQUEST_METHOD']==='POST'){ $repo->updateRoleStatus((int)$_POST['id'],(int)$_POST['role_id'],$_POST['status']); flash('success','Đã cập nhật phân quyền'); redirect_to('users/index.php'); } $title='Người dùng hệ thống'; include ROOT_PATH.'/includes/header.php'; ?><div class="d-flex justify-content-between align-items-center mb-3"><h1 class="h3 mb-0">Người dùng hệ thống</h1></div><div class="table-responsive"><table class="table table-bordered table-striped"><tr><th>Họ tên</th><th>Email</th><th>Mã SV</th><th>Lớp</th><th>Ngành</th><th>Vai trò</th><th>Trạng thái</th><th class="table-actions-nowrap" width="360">Thao tác</th></tr><?php foreach($rows as $u): ?><tr><td><?= e($u['full_name']) ?></td><td><?= e($u['email']) ?></td><td><?= e($u['student_code']) ?></td><td><?= e($u['class_name']) ?></td><td><?= e($u['major']) ?></td><td><?= e($u['role_display']) ?></td><td><?= e($u['status']) ?></td><td class="table-actions-nowrap"><form method="post" class="user-actions"><input type="hidden" name="id" value="<?= $u['id'] ?>"><select name="role_id" class="form-select form-select-sm w-role"><?php foreach($roles as $r): ?><option value="<?= $r['id'] ?>" <?= selected($u['role_name'],$r['name']) ?>><?= e($r['display_name']) ?></option><?php endforeach; ?></select><select name="status" class="form-select form-select-sm w-status"><option value="active" <?= selected($u['status'],'active') ?>>active</option><option value="inactive" <?= selected($u['status'],'inactive') ?>>inactive</option></select><button class="btn btn-sm btn-primary" type="submit">Lưu</button><a data-confirm="Xóa người dùng này?" class="btn btn-sm btn-danger" href="delete.php?id=<?= $u['id'] ?>">Xóa</a></form></td></tr><?php endforeach; ?></table></div><?php include ROOT_PATH.'/includes/footer.php'; ?>
